    cin.tie(0);
#define endl '\n'
#define f first
#define s second

typedef unsigned long long llu;
typedef unsigned int ui;
typedef long long ll;

bool is_op(char& c)
{
    if (c == '+' || c == '-' || c == '*' || c == '/')
        return true;
    return false;
}

bool is_digit(char& c)
{
    if (c >= '0' && c <= '9')
        return true;
    return false;
}

int main()
{
    //_
    string entrada;
    cin >> entrada;
    string limpa = "";
    for (char& c : entrada)
    {
        if (is_digit(c) || is_op(c))
            limpa += c;
    }

    vector<string> valores;
    vector<char> operadores;
    string aux = "";
    for (char& c : limpa)
    {
        if (is_digit(c))
            aux += c;
        if (is_op(c))
        {
            valores.push_back(aux);
            aux = "";
            operadores.push_back(c);
        }
    }
    valores.push_back(aux);

    double res, num;
    int i = 0;
    res = stod(valores.at(i++));

    for (char& op : operadores)
    {
        num = stod(valores.at(i++));
        if (op == '+')
            res += num;
        else if (op == '-')
            res -= num;
        else if (op == '*')
            res *= num;
        else if (op == '/')
        {
            if (num == 0)
            {
                cout << "caiu os butcha dos bolsos\n";
                return 0;
            }
            else
            {
                res /= num;
            }
        }
    }
    cout << fixed << setprecision(2) << res << endl;
    return 0;
}
